dslRule:
/*!id: jdt.internal.refactoring.abstractunnamedtypedec.to.abstracttypedec.type*/
/*!description: Replaces type reference AbstractUnnamedTypeDeclaration with AbstractTypeDeclaration, reflecting JDT Core DOM AST changes.*/
/*!severity: info*/
org.eclipse.jdt.core.dom.AbstractUnnamedTypeDeclaration
=> org.eclipse.jdt.core.dom.AbstractTypeDeclaration
;;

/*!id: jdt.internal.refactoring.abstractunnamedtypedec.to.abstracttypedec.expression*/
/*!description: Simplifies ternary expression related to AbstractUnnamedTypeDeclaration to direct getName() call, reflecting JDT Core DOM AST changes.*/
/*!severity: info*/
$type instanceof org.eclipse.jdt.core.dom.AbstractTypeDeclaration named? named.getName().getIdentifier() : ""
=> $type.getName().getIdentifier()
;;

@id: jdt.internal.quickfixprocessor.npe.fix
@severity: error
!(deprecatedMethodNode instanceof org.eclipse.jdt.core.dom.MethodInvocation)
:: inClass("org.eclipse.jdt.internal.ui.text.correction.QuickFixProcessor") && inMethod("getProposals")
=> deprecatedMethodNode != null && !(deprecatedMethodNode instanceof org.eclipse.jdt.core.dom.MethodInvocation)
;;

/*!id: jdt.internal.remove-redundant-cast.table*/
/*!description: Removes redundant (Table) casts when the expression is already a subtype of Table.*/
/*!severity: info*/
(org.eclipse.swt.widgets.Table) $expression :: subtypeOf($expression, "org.eclipse.swt.widgets.Table")
=> $expression
;;

