/*!id: jdt.internal.jls.version13.to.firstsupported*/
/*!description: Updates internal JDT UI code to replace specific JavaCore version constants with dynamic calls to getFirstJavaSourceVersionSupportedByCompiler().*/
/*!severity: info*/
org.eclipse.jdt.core.JavaCore.VERSION_1_3
=> org.eclipse.jdt.core.JavaCore.getFirstJavaSourceVersionSupportedByCompiler()
;;

/*!id: jdt.internal.jls.version11.to.firstsupported*/
/*!description: Updates internal JDT UI code to replace specific JavaCore version constants with dynamic calls to getFirstJavaSourceVersionSupportedByCompiler().*/
/*!severity: info*/
org.eclipse.jdt.core.JavaCore.VERSION_1_1
=> org.eclipse.jdt.core.JavaCore.getFirstJavaSourceVersionSupportedByCompiler()
;;

/*!id: jdt.internal.compliance.remove-version13-check*/
/*!description: Simplifies a boolean expression by removing a redundant check against JavaCore.VERSION_1_3, reflecting dropped support for older Java versions.*/
/*!severity: info*/
!org.eclipse.jdt.core.JavaCore.VERSION_1_3.equals($source) && $versionCheck
=> $versionCheck
;;

/*!id: jdt.internal.javamodutil.getcompilercompliance.version14.to.firstsupported*/
/*!description: Updates calls to JavaModelUtil.getCompilerCompliance() to use getFirstJavaSourceVersionSupportedByCompiler() instead of a hardcoded Java 1.4 version.*/
/*!severity: info*/
org.eclipse.jdt.internal.corext.util.JavaModelUtil.getCompilerCompliance($vmInstall, org.eclipse.jdt.core.JavaCore.VERSION_1_4)
=> org.eclipse.jdt.internal.corext.util.JavaModelUtil.getCompilerCompliance($vmInstall, org.eclipse.jdt.core.JavaCore.getFirstJavaSourceVersionSupportedByCompiler())
;;

/*!id: jdt.internal.jls.issupportedjavaversion.to.issourcesupportedbycompiler*/
/*!description: Updates internal JavaCore API calls from isSupportedJavaVersion() to isJavaSourceVersionSupportedByCompiler() for improved precision.*/
/*!severity: info*/
org.eclipse.jdt.core.JavaCore.isSupportedJavaVersion($versionStr)
=> org.eclipse.jdt.core.JavaCore.isJavaSourceVersionSupportedByCompiler($versionStr)
;;

/*!id: jdt.internal.runtime.getexecutionenvironments.to.getsupported*/
/*!description: Updates internal JavaRuntime API calls from getExecutionEnvironments() to getSupportedExecutionEnvironments() to reflect dropped support for older Java versions.*/
/*!severity: info*/
org.eclipse.jdt.launching.JavaRuntime.getExecutionEnvironmentsManager().getExecutionEnvironments()
=> org.eclipse.jdt.launching.JavaRuntime.getExecutionEnvironmentsManager().getSupportedExecutionEnvironments()
;;

/*!id: jdt.internal.versions.addall.allversions.to.alljavasourceversions*/
/*!description: Updates internal JavadocSpecificsWizardPage to use getAllJavaSourceVersionsSupportedByCompiler() for populating versions list.*/
/*!severity: info*/
$versions.addAll(org.eclipse.jdt.core.JavaCore.getAllVersions())
=> $versions.addAll(org.eclipse.jdt.core.JavaCore.getAllJavaSourceVersionsSupportedByCompiler())
;;

"Menu item action for building & presenting color preferences sub-menu of javadoc styling menu."
=> "Menu item action for building &amp; presenting color preferences sub-menu of javadoc styling menu."
;;

/*!id: jdt.internal.javacore.getfirstjavasourceversion-to-getalljavasourceversions.first*/
/*!description: Replaces JavaCore.getFirstJavaSourceVersionSupportedByCompiler() with getAllJavaSourceVersionsSupportedByCompiler().first() to use updated internal API.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring, api-modernization*/
org.eclipse.jdt.core.JavaCore.getFirstJavaSourceVersionSupportedByCompiler()
=> org.eclipse.jdt.core.JavaCore.getAllJavaSourceVersionsSupportedByCompiler().first()
;;

@id: jdt.internal.quickfix.addserviceprovider.cce-fix
@severity: error
!($node instanceof org.eclipse.jdt.core.dom.Name) && !($node.getParent() instanceof org.eclipse.jdt.core.dom.ProvidesDirective)
:: inClass("org.eclipse.jdt.internal.ui.text.correction.LocalCorrectionsSubProcessor")
=> !($node instanceof org.eclipse.jdt.core.dom.Name) || !($node.getParent() instanceof org.eclipse.jdt.core.dom.ProvidesDirective)
;;
